
.stats-panel {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.section {
  background: var(--bg-card);
  border-radius: 8px;
  padding: 10px 12px;
}

.section-title {
  font-weight: bold;
  color: var(--accent-gold);
  font-size: 12px;
  text-transform: uppercase;
  letter-spacing: 1px;
  margin-bottom: 8px;
}

// Attributes
.stats-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 4px 16px;
}

.stat {
  display: flex;
  justify-content: space-between;
  font-size: 12px;
  padding: 2px 0;

  .stat-label { color: var(--text-secondary); }
  .stat-value { color: var(--accent-gold); font-weight: bold; }
}

// Spank Stats
.total-spanks {
  font-size: 14px;
  color: var(--accent-red);
  font-weight: bold;
  margin-bottom: 8px;
}

.spank-list {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.spank-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  font-size: 12px;
  padding: 2px 0;
}

.spank-name {
  color: var(--text-primary);
}

.spank-count {
  color: var(--accent-pink);
  font-weight: 700;
  font-size: 13px;
}

// Achievements
.ach-row {
  font-size: 11px;
  padding: 2px 0;
  display: flex;
  align-items: center;
  gap: 4px;
}

.ach-done {
  color: var(--accent-green);
  font-weight: bold;
}

.ach-pending {
  color: var(--text-muted);
}

.ach-text-done {
  color: var(--accent-green);
}

.ach-text-pending {
  color: var(--text-muted);
}
