
.quest-panel {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.section {
  background: var(--bg-card);
  border-radius: 8px;
  padding: 10px 12px;
}

.section-title {
  font-weight: bold;
  margin-bottom: 8px;
  color: var(--accent-gold);
  font-size: 12px;
  text-transform: uppercase;
  letter-spacing: 1px;
}

.info-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 4px 16px;
}

.info-row {
  display: flex;
  justify-content: space-between;
  font-size: 12px;
  padding: 2px 0;

  .label { color: var(--text-secondary); }
  .value { color: var(--text-primary); }
  .route-a { color: var(--accent-green); font-weight: bold; }
  .route-b { color: var(--accent-red); font-weight: bold; }
}

// Main Quest
.main-quest-card {
  background: var(--bg-elevated);
  border-radius: 6px;
  padding: 10px;
  border-left: 3px solid var(--accent-gold);

  .mq-name {
    font-size: 13px;
    color: var(--accent-gold);
    font-weight: bold;
    margin-bottom: 4px;
  }
  .mq-detail {
    font-size: 11px;
    color: var(--text-primary);
    line-height: 1.5;
  }
}

// Main Quest Objectives
.empty {
  color: var(--text-muted);
  font-style: italic;
  font-size: 12px;
}

.task-item {
  padding: 5px 8px;
  border-radius: 4px;
  margin-bottom: 4px;
  border-left: 3px solid var(--border-color);

  .task-name { font-size: 12px; color: var(--text-primary); font-weight: 600; }
  .task-desc { font-size: 11px; color: var(--text-secondary); margin-top: 2px; }
}

// Side Quest Tabs
.sq-tabs {
  display: flex;
  gap: 0;
  background: var(--bg-card);
  border-radius: 6px;
  overflow: hidden;
  margin-bottom: 8px;
}

.sq-tab {
  flex: 1;
  padding: 6px 8px;
  background: none;
  border: none;
  border-bottom: 2px solid transparent;
  color: var(--text-muted);
  cursor: pointer;
  font-size: 11px;
  font-weight: 600;
  transition: all 0.2s;

  &:hover {
    color: var(--text-primary);
    background: var(--hover-bg);
  }

  &.active {
    color: var(--accent-gold);
    border-bottom-color: var(--accent-gold);
  }
}

.sq-tab-count {
  font-size: 10px;
  font-weight: 700;
  margin-left: 3px;

  .sq-tab.active & {
    color: var(--accent-gold);
  }
}

// Side Quest Grid
.sq-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 6px;
  max-height: 300px;
  overflow-y: auto;
  padding-right: 2px;
}

.sq-card {
  background: var(--bg-elevated);
  border: 1px solid var(--border-light);
  border-radius: 6px;
  padding: 7px 9px;
  transition: border-color 0.2s;
  display: flex;
  flex-direction: column;
  gap: 2px;

  &.sq-available {
    border-color: var(--accent-green);
  }

  &.sq-done {
    opacity: 0.5;
  }
}

.sq-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.sq-char {
  font-size: 12px;
  font-weight: bold;
}

.sq-id {
  font-size: 10px;
  color: var(--text-muted);
  font-weight: 600;
}

.sq-title {
  font-size: 11px;
  color: var(--text-primary);
}

.sq-conds {
  font-size: 10px;
  display: flex;
  flex-direction: column;
  gap: 1px;
}

.sq-cond {
  color: var(--text-secondary);
  display: flex;
  align-items: center;
  gap: 3px;

  .cond-met { color: var(--accent-green); }
  .cond-fail { color: var(--text-muted); }
}

.sq-status {
  margin-top: 2px;
  font-size: 10px;
  font-weight: 600;

  .badge-ready { color: var(--accent-green); }
  .badge-lock { color: var(--text-muted); }
  .badge-done { color: var(--accent-green); }
}
