
.character-panel {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
  gap: 10px;
  max-height: 480px;
  overflow-y: auto;
  padding-right: 2px;
}

.char-card {
  background: var(--bg-card);
  border: 1px solid var(--border-light);
  border-radius: 8px;
  padding: 10px 12px;
  display: flex;
  flex-direction: column;
  gap: 6px;
  transition: border-color 0.2s;

  &:hover {
    background: var(--hover-bg);
  }

  &.char-present {
    border-color: rgba(129, 199, 132, 0.3);
  }

  &.char-unknown {
    opacity: 0.4;
  }
}

// Header
.char-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
}

.char-name-row {
  display: flex;
  align-items: center;
  gap: 4px;
}

.char-name {
  font-size: 13px;
  font-weight: bold;
  color: var(--text-primary);
}

.presence-dot {
  color: var(--accent-green);
  font-size: 7px;
  line-height: 1;
}

.char-role {
  font-size: 10px;
  color: var(--text-muted);
}

// Affection
.affection-section {
  display: flex;
  flex-direction: column;
  gap: 3px;
}

.affection-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.aff-label {
  font-size: 11px;
  color: var(--text-secondary);
}

.aff-value {
  font-size: 14px;
  font-weight: 800;
}

.affection-bar {
  height: 5px;
  background: var(--bg-elevated);
  border-radius: 3px;
  overflow: hidden;
}

.affection-fill {
  height: 100%;
  border-radius: 3px;
  transition: width 0.5s ease;
}

// Butt Status
.butt-section {
  display: flex;
  flex-direction: column;
  gap: 3px;
}

.butt-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.butt-label {
  font-size: 11px;
  color: var(--text-secondary);
}

.butt-value {
  font-size: 11px;
  font-weight: 700;
}

.butt-normal {
  font-size: 11px;
  color: var(--text-muted);
}

.butt-bar-track {
  height: 3px;
  background: var(--bg-elevated);
  border-radius: 2px;
  overflow: hidden;
}

.butt-bar-fill {
  height: 100%;
  border-radius: 2px;
  transition: width 0.8s linear;
}

// SQ Section
.sq-section {
  display: flex;
  align-items: center;
  gap: 6px;
}

.sq-label {
  font-size: 10px;
  color: var(--text-muted);
  font-weight: 600;
}

.sq-badges {
  display: flex;
  gap: 3px;
  flex-wrap: wrap;
}

.sq-badge {
  font-size: 11px;
  width: 18px;
  height: 18px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 4px;
  font-weight: 700;

  &.sq-done {
    background: rgba(129, 199, 132, 0.15);
    color: var(--accent-green);
  }

  &.sq-pending {
    background: rgba(85, 85, 119, 0.15);
    color: var(--text-muted);
  }
}
