
.inventory-panel {
  display: flex;
  flex-direction: column;
  gap: 10px;
  max-height: 480px;
  overflow-y: auto;
  padding-right: 2px;
}

.inv-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.section-title {
  font-weight: bold;
  color: var(--accent-gold);
  font-size: 12px;
  text-transform: uppercase;
  letter-spacing: 1px;
}

.gold-display {
  font-size: 13px;
  color: var(--accent-money);
  font-weight: 700;
}

.empty {
  color: var(--text-muted);
  font-style: italic;
  font-size: 12px;
}

// Category Tabs
.cat-tabs {
  display: flex;
  gap: 0;
  background: var(--bg-card);
  border-radius: 6px;
  overflow: hidden;
}

.cat-tab {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 1px;
  padding: 6px 4px;
  background: none;
  border: none;
  border-bottom: 2px solid transparent;
  color: var(--text-muted);
  cursor: pointer;
  font-size: 10px;
  transition: all 0.2s;

  &:hover {
    color: var(--text-primary);
    background: var(--hover-bg);
  }

  &.active {
    color: var(--accent-gold);
    border-bottom-color: var(--accent-gold);
  }
}

.cat-tab-icon {
  font-size: 14px;
}

.cat-tab-label {
  font-size: 10px;
  font-weight: 600;
}

.cat-tab-count {
  font-size: 10px;
  font-weight: 700;
  min-width: 16px;
  text-align: center;
  border-radius: 8px;
  padding: 0 4px;

  .cat-tab.active & {
    background: rgba(255, 204, 128, 0.15);
  }
}

// Item Grid
.item-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(150px, 1fr));
  gap: 6px;
}

.item-card {
  background: var(--bg-card);
  border: 1px solid var(--border-light);
  border-radius: 6px;
  padding: 8px 10px;
  display: flex;
  flex-direction: column;
  gap: 2px;
  position: relative;
  transition: background 0.15s;

  &:hover {
    background: var(--hover-bg);
  }
}

.item-name {
  font-size: 12px;
  color: var(--text-primary);
  font-weight: 600;
  padding-right: 32px;
}

.item-count {
  position: absolute;
  top: 6px;
  right: 8px;
  font-size: 12px;
  color: var(--accent-gold);
  font-weight: 700;
}

.item-desc {
  font-size: 10px;
  color: var(--text-secondary);
  line-height: 1.4;
  margin-top: 2px;
}

.cat-empty {
  font-size: 11px;
  color: var(--text-muted);
  font-style: italic;
  text-align: center;
  padding: 16px 0;
}
